export enum UserRole {
  ADMIN = 'ADMIN',
  COORDINATOR = 'COORDINATOR',
  ANALYST = 'ANALYST',
}

export interface User {
  id: string;
  email: string;
  name: string;
  nickname?: string;
  role: UserRole;
  avatar: string;
  organization: string;
  password?: string;
  active?: boolean;
  canAccessReports?: boolean;
  canAccessReferents?: boolean;
}

export interface Referent {
  id: string;
  name: string;
  email: string;
  specialty: string;
  organization: string;
}

export enum DocState {
  NOT_STARTED = 'NOT_STARTED',
  INITIATED = 'INITIATED',
  IN_PROCESS = 'IN_PROCESS',
  INTERNAL_REVIEW = 'INTERNAL_REVIEW',
  SENT_TO_REFERENT = 'SENT_TO_REFERENT',
  REFERENT_REVIEW = 'REFERENT_REVIEW',
  SENT_TO_CONTROL = 'SENT_TO_CONTROL',
  CONTROL_REVIEW = 'CONTROL_REVIEW',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export type DocType = 'AS IS' | 'FCE' | 'PM' | 'TO BE';

export interface DocFile {
  id: string;
  name: string;
  size: number;
  type: string;
  url: string;
  uploadedAt: string;
}

export interface DocHistory {
  id: string;
  documentId: string;
  userId: string;
  userName: string;
  action: string;
  previousState: DocState;
  newState: DocState;
  comment: string;
  timestamp: string;
}

export interface Notification {
  id: string;
  userId: string;
  documentId: string;
  type: 'ASSIGNMENT' | 'APPROVAL' | 'REJECTION' | 'COMMENT';
  title: string;
  message: string;
  isRead: boolean;
  timestamp: string;
  actorName: string;
}

